package com.waterbuddy;
import android.app.*;import android.content.*;import android.os.*;import android.speech.tts.TextToSpeech;import java.util.*;
public class ReminderReceiver extends BroadcastReceiver {
 static final String CHANNEL="water";
 @Override public void onReceive(Context c,Intent i){String action=i.getAction(); SharedPreferences p=c.getSharedPreferences("water",Context.MODE_PRIVATE);if("DRANK".equals(action)){p.edit().putInt("glasses",p.getInt("glasses",0)+1).apply();NotificationManager n=c.getSystemService(NotificationManager.class);n.cancel(7);return;} if("VOICE".equals(action)){boolean on=!p.getBoolean("voice",true);p.edit().putBoolean("voice",on).apply();show(c);return;} show(c);}
 static PendingIntent act(Context c,String a,int id){return PendingIntent.getBroadcast(c,id,new Intent(c,ReminderReceiver.class).setAction(a),PendingIntent.FLAG_UPDATE_CURRENT|PendingIntent.FLAG_IMMUTABLE);}
 static void show(Context c){SharedPreferences p=c.getSharedPreferences("water",Context.MODE_PRIVATE);boolean on=p.getBoolean("voice",true);Notification.Builder b=new Notification.Builder(c,CHANNEL).setSmallIcon(android.R.drawable.ic_dialog_info).setContentTitle("💧 Drink water, cutie!").setContentText("It is sip sip time!").setPriority(Notification.PRIORITY_HIGH).setAutoCancel(true).addAction(new Notification.Action.Builder(null,"I drank water",act(c,"DRANK",11)).build()).addAction(new Notification.Action.Builder(null,on?"🔊 Voice: On":"🔇 Voice: Off",act(c,"VOICE",12)).build());c.getSystemService(NotificationManager.class).notify(7,b.build());if(on)new TextToSpeech(c,(tts,status)->{if(status==TextToSpeech.SUCCESS){tts.setPitch(1.65f);tts.setSpeechRate(.9f);tts.speak("Drink water, cutie! It is sip sip time!",TextToSpeech.QUEUE_FLUSH,null,"water");}});}
}
